// ============================================================
// DOCTOR TRUST - Normaliza lo que llega del widget
// Salida: { sessionId, message, image, hasImage }
// ============================================================

const body = $input.first().json.body || {};

const message = String(body.message || '').slice(0, 1000).trim();
const image = body.image || null;

return [{
  json: {
    sessionId: body.sessionId || 'anonimo',
    message: message || (image ? 'El cliente subio una foto de su planta sin escribir texto.' : 'Hola'),
    image: image,
    hasImage: !!image,
    page: (body.meta && body.meta.page) || ''
  }
}];

// ============================================================
// DOCTOR TRUST - Fusiona el analisis de la foto con el mensaje
// ============================================================

const prep = $('Preparar entrada').first().json;

let analisis = '';
try {
  analisis = $input.first().json.choices[0].message.content || '';
} catch (e) {
  analisis = '';
}

const prompt = analisis
  ? 'El cliente subio una FOTO de su cultivo. Analisis visual de la imagen:\n"""\n' + analisis + '\n"""\n\nMensaje del cliente: ' + prep.message
  : prep.message + '\n\n(Nota: el cliente subio una foto pero no se pudo analizar. Pidele que la vuelva a enviar con buena luz y de cerca.)';

return [{ json: { prompt: prompt, sessionId: prep.sessionId } }];

// Sin foto: pasa el mensaje tal cual al agente
const j = $input.first().json;
return [{ json: { prompt: j.message, sessionId: j.sessionId } }];

// ============================================================
// DOCTOR TRUST - Formatea la respuesta segun el contrato del widget
// El AI Agent devuelve el texto en $json.output
// ============================================================

let raw = String($input.first().json.output || '').trim();

// El modelo a veces envuelve el JSON en ```json ... ``` -> lo limpiamos
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();

let data;
try {
  data = JSON.parse(raw);
} catch (e) {
  // Si no es JSON, usamos el texto tal cual como respuesta
  data = { reply: raw, products: [], needsHuman: false };
}

const reply = (data.reply && String(data.reply).trim())
  ? String(data.reply)
  : 'No pude procesar tu consulta en este momento. Te paso con un asesor.';

// Solo permitimos URLs de nuestras lineas (evita que el modelo invente enlaces)
const OK_URLS = ['lineas.html#ynsufert', 'lineas.html#ynsumaq', 'lineas.html#ynsupack', 'lineas.html#ynsugrow'];
const products = Array.isArray(data.products)
  ? data.products.filter(p => p && p.nombre && OK_URLS.includes(p.url)).slice(0, 2)
  : [];

return [{
  json: {
    ok: true,
    reply: reply,
    products: products,
    needsHuman: data.needsHuman === true
  }
}];

// Fallback: si el agente falla, el widget igual recibe una respuesta valida
return [{
  json: {
    ok: false,
    reply: 'Disculpa, tuve un problema tecnico al procesar tu consulta. Puedes intentar de nuevo o hablar directo con un asesor.',
    products: [],
    needsHuman: true
  }
}];
